from selenium import webdriver
import boto3
import time

s3 = boto3.resource('s3')
bucket_name = 'your-bucket-name'  # replace with your bucket name

def take_screenshot(url):
    driver = webdriver.Chrome()
    driver.get(url)
    
    screenshot_filepath = f'/tmp/{int(time.time())}.png'  
    driver.save_screenshot(screenshot_filepath)  # Saves screenshot to file
    driver.quit()
      
    return screenshot_filepath

def upload_to_s3(filepath):
    with open(filepath, 'rb') as data:
        s3.Bucket(bucket_name).put_object(Key='screenshot.png', Body=data)
        
url = 'https://www.example.com'  # replace with the URL you want to screenshot
screenshot_filepath = take_screenshot(url)
upload_to_s3(screenshot_filepath)